14	use core::convert::TryFrom;
15	
16	use zenoh_buffers::{
17	    reader::{DidntRead, Reader},
18	    writer::{DidntWrite, Writer},
19	};
20	use zenoh_codec::{RCodec, WCodec, Zenoh080};
21	use zenoh_protocol::{
22	    common::imsg,
23	    core::{Locator, WhatAmI, ZenohIdProto},
24	};
25	
26	use super::Zenoh080Routing;
27	use crate::net::protocol::{
28	    linkstate,
29	    linkstate::{LinkState, LinkStateList},
30	};
31	
32	// LinkState
33	impl<W> WCodec<&LinkState, &mut W> for Zenoh080Routing
34	where
35	    W: Writer,
36	{
37	    type Output = Result<(), DidntWrite>;
38	
39	    fn write(self, writer: &mut W, x: &LinkState) -> Self::Output {
40	        let codec = Zenoh080::new();
41	        // Options
42	        let mut options = 0;
43	        if x.zid.is_some() {
44	            options |= linkstate::PID;
45	        }
46	        if x.whatami.is_some() {
47	            options |= linkstate::WAI;
48	        }
49	        if x.locators.is_some() {
50	            options |= linkstate::LOC;
51	        }
52	        if x.link_weights.is_some() {
53	            options |= linkstate::WGT;
54	        }
55	        if x.is_gateway {
56	            options |= linkstate::GWY;
57	        }
58	        codec.write(&mut *writer, options)?;
59	
60	        // Body
61	        codec.write(&mut *writer, x.psid)?;
62	        codec.write(&mut *writer, x.sn)?;
63	        if let Some(zid) = x.zid.as_ref() {
64	            codec.write(&mut *writer, zid)?;
65	        }
66	        if let Some(wai) = x.whatami {
67	            let wai: u8 = wai.into();
68	            codec.write(&mut *writer, wai)?;
69	        }
70	        if let Some(locators) = x.locators.as_ref() {
71	            codec.write(&mut *writer, locators.as_slice())?;
72	        }
73	        codec.write(&mut *writer, x.links.len())?;
74	        for l in x.links.iter() {
75	            codec.write(&mut *writer, *l)?;
76	        }
77	        if let Some(link_weights) = x.link_weights.as_ref() {
78	            // do not write len since it is the same as that of links
79	            for w in link_weights.iter() {
80	                codec.write(&mut *writer, w)?;
81	            }
82	        }
83	
84	        Ok(())
85	    }
86	}
87	
88	impl<R> RCodec<LinkState, &mut R> for Zenoh080Routing
89	where
90	    R: Reader,
91	{
92	    type Error = DidntRead;
93	
94	    fn read(self, reader: &mut R) -> Result<LinkState, Self::Error> {
95	        let codec = Zenoh080::new();
96	        let options: u64 = codec.read(&mut *reader)?;
97	        let psid: u64 = codec.read(&mut *reader)?;
98	        let sn: u64 = codec.read(&mut *reader)?;
99	        let zid = if imsg::has_option(options, linkstate::PID) {
100	            let zid: ZenohIdProto = codec.read(&mut *reader)?;
101	            Some(zid)
102	        } else {
103	            None
104	        };
105	        let whatami = if imsg::has_option(options, linkstate::WAI) {
106	            let wai: u8 = codec.read(&mut *reader)?;
107	            Some(WhatAmI::try_from(wai).map_err(|_| DidntRead)?)
108	        } else {
109	            None
110	        };
111	        let locators = if imsg::has_option(options, linkstate::LOC) {
112	            let locs: Vec<Locator> = codec.read(&mut *reader)?;
113	            Some(locs)
114	        } else {
115	            None
116	        };
117	        let links_len: usize = codec.read(&mut *reader)?;
118	        let mut links: Vec<u64> = Vec::with_capacity(links_len);
119	        for _ in 0..links_len {
120	            let l: u64 = codec.read(&mut *reader)?;
121	            links.push(l);
122	        }
123	
124	        let link_weights = if imsg::has_option(options, linkstate::WGT) {
125	            // number of weights is the same as number of links
126	            let mut weights: Vec<u16> = Vec::with_capacity(links_len);
127	            for _ in 0..links_len {
128	                let w: u16 = codec.read(&mut *reader)?;
129	                weights.push(w);
130	            }
131	            Some(weights)
132	        } else {
133	            None
134	        };
135	
136	        let is_gateway = imsg::has_option(options, linkstate::GWY);
137	
138	        Ok(LinkState {
139	            psid,
140	            sn,
141	            zid,
142	            whatami,
143	            locators,
144	            links,
145	            link_weights,
146	            is_gateway,
147	        })
148	    }
149	}
150	
151	// LinkStateList
152	impl<W> WCodec<&LinkStateList, &mut W> for Zenoh080Routing
153	where
154	    W: Writer,
155	{
156	    type Output = Result<(), DidntWrite>;
157	
158	    fn write(self, writer: &mut W, x: &LinkStateList) -> Self::Output {
159	        let codec = Zenoh080::new();
160	
161	        codec.write(&mut *writer, x.link_states.len())?;
162	        for ls in x.link_states.iter() {
163	            self.write(&mut *writer, ls)?;
164	        }
165	
166	        Ok(())
167	    }
168	}
169	
170	impl<R> RCodec<LinkStateList, &mut R> for Zenoh080Routing
171	where
172	    R: Reader,
173	{
174	    type Error = DidntRead;
175	
176	    fn read(self, reader: &mut R) -> Result<LinkStateList, Self::Error> {
177	        let codec = Zenoh080::new();
178	
179	        let len: usize = codec.read(&mut *reader)?;
180	        let mut link_states = Vec::with_capacity(len);
181	        for _ in 0..len {
182	            let ls: LinkState = self.read(&mut *reader)?;
183	            link_states.push(ls);
184	        }
185	
186	        Ok(LinkStateList { link_states })
187	    }
188	}
