116	impl Gossip {
117	    #[allow(clippy::too_many_arguments)]
118	    pub(crate) fn new(
119	        name: String,
120	        zid: ZenohIdProto,
121	        runtime: Runtime,
122	        gossip_target: WhatAmIMatcher,
123	        autoconnect: AutoConnect,
124	        wait_declares: bool,
125	    ) -> Self {
126	        let mut graph = petgraph::stable_graph::StableGraph::default();
127	        tracing::debug!("{} Add node (self) {}", name, zid);
128	        let idx = graph.add_node(Node {
129	            zid,
130	            whatami: Some(runtime.whatami()),
131	            locators: None,
132	            sn: 1,
133	            is_gateway: false,
134	        });
135	        Gossip {
136	            name,
137	            gossip_target,
138	            autoconnect,
139	            wait_declares,
140	            idx,
141	            links: VecMap::new(),
142	            graph,
143	            runtime: Runtime::downgrade(&runtime),
144	        }
145	    }
146	
147	    pub(crate) fn dot(&self) -> String {
148	        std::format!("{:?}", petgraph::dot::Dot::new(&self.graph))
149	    }
150	
151	    #[inline]
152	    fn get_idx(&self, zid: &ZenohIdProto) -> Option<NodeIndex> {
153	        self.graph
154	            .node_indices()
155	            .find(|idx| self.graph[*idx].zid == *zid)
156	    }
157	
158	    fn add_node(&mut self, node: Node) -> NodeIndex {
159	        let zid = node.zid;
160	        let idx = self.graph.add_node(node);
161	        for link in self.links.values_mut() {
162	            if let Some((psid, _)) = link.mappings.iter().find(|(_, p)| **p == zid) {
163	                link.local_mappings.insert(psid, idx.index() as u64);
164	            }
165	        }
166	        idx
167	    }
168	
169	    fn make_link_state(&self, idx: NodeIndex, details: Details) -> LinkState {
170	        let links = if details.links && idx == self.idx {
171	            self.links
172	                .iter()
173	                .filter_map(|(_, link)| {
174	                    if let Some(idx2) = self.get_idx(&link.zid) {
175	                        Some(idx2.index().try_into().unwrap())
176	                    } else {
177	                        tracing::error!(
178	                            "{} Internal error building link state: cannot get index of {}",
179	                            self.name,
180	                            link.zid,
181	                        );
182	                        None
183	                    }
184	                })
185	                .collect()
186	        } else {
187	            vec![]
188	        };
189	        LinkState {
190	            psid: idx.index().try_into().unwrap(),
191	            sn: self.graph[idx].sn,
192	            zid: if details.zid {
193	                Some(self.graph[idx].zid)
194	            } else {
195	                None
196	            },
197	            whatami: self.graph[idx].whatami,
198	            locators: if details.locators {
199	                if idx == self.idx {
200	                    Some(self.runtime.upgrade().unwrap().get_locators())
201	                } else {
202	                    self.graph[idx].locators.clone()
203	                }
204	            } else {
205	                None
206	            },
207	            links,
208	            link_weights: None,
209	            is_gateway: self.graph[idx].is_gateway,
210	        }
211	    }
212	
213	    fn make_msg(&self, idxs: Vec<(NodeIndex, Details)>) -> Result<NetworkMessage, DidntWrite> {
214	        let mut link_states = vec![];
215	        for (idx, details) in idxs {
216	            link_states.push(self.make_link_state(idx, details));
217	        }
218	        let codec = Zenoh080Routing::new();
219	        let mut buf = ZBuf::empty();
220	        codec.write(&mut buf.writer(), &LinkStateList { link_states })?;
221	        Ok(NetworkBody::OAM(Oam {
222	            id: OAM_LINKSTATE,
223	            body: ZExtBody::ZBuf(buf),
224	            ext_qos: oam::ext::QoSType::OAM,
225	            ext_tstamp: None,
226	        })
227	        .into())
228	    }
