230	    fn send_on_link(&self, idxs: Vec<(NodeIndex, Details)>, transport: &TransportUnicast) {
231	        if transport
232	            .get_whatami()
233	            .is_ok_and(|w| self.gossip_target.matches(w))
234	        {
235	            if let Ok(mut msg) = self.make_msg(idxs) {
236	                tracing::trace!("{} Send to {:?} {:?}", self.name, transport.get_zid(), msg);
237	                if let Err(e) = transport.schedule(msg.as_mut()) {
238	                    tracing::debug!("{} Error sending LinkStateList: {}", self.name, e);
239	                }
240	            } else {
241	                tracing::error!("Failed to encode Linkstate message");
242	            }
243	        }
244	    }
245	
246	    fn send_on_links<P>(&self, idxs: Vec<(NodeIndex, Details)>, mut parameters: P)
247	    where
248	        P: FnMut(&Link) -> bool,
249	    {
250	        if let Ok(msg) = self.make_msg(idxs) {
251	            for link in self.links.values() {
252	                if link
253	                    .transport
254	                    .get_whatami()
255	                    .is_ok_and(|w| self.gossip_target.matches(w))
256	                    && parameters(link)
257	                {
258	                    tracing::trace!("{} Send to {} {:?}", self.name, link.zid, msg);
259	                    if let Err(e) = link.transport.schedule(msg.clone().as_mut()) {
260	                        tracing::debug!("{} Error sending LinkStateList: {}", self.name, e);
261	                    }
262	                }
263	            }
264	        } else {
265	            tracing::error!("Failed to encode Linkstate message");
266	        }
267	    }
268	
269	    pub(crate) fn link_states(
270	        &mut self,
271	        link_states: Vec<LinkState>,
272	        src: ZenohIdProto,
273	        src_whatami: WhatAmI,
274	    ) {
275	        tracing::trace!("{} Received from {} raw: {:?}", self.name, src, link_states);
276	        let strong_runtime = self.runtime.upgrade().unwrap();
277	
278	        let graph = &self.graph;
279	        let links = &mut self.links;
280	
281	        let src_link = match links.values_mut().find(|link| link.zid == src) {
282	            Some(link) => link,
283	            None => {
284	                tracing::error!(
285	                    "{} Received LinkStateList from unknown link {}",
286	                    self.name,
287	                    src
288	                );
289	                return;
290	            }
291	        };
292	
293	        // register psid<->zid mappings & apply mapping to nodes
294	        let link_states = link_states
295	            .into_iter()
296	            .filter_map(|link_state| {
297	                if let Some(zid) = link_state.zid {
298	                    src_link.set_zid_mapping(link_state.psid, zid);
299	                    if let Some(idx) = graph.node_indices().find(|idx| graph[*idx].zid == zid) {
300	                        src_link.set_local_psid_mapping(link_state.psid, idx.index() as u64);
301	                    }
302	                    Some((
303	                        zid,
304	                        link_state.whatami.unwrap_or(WhatAmI::Router),
305	                        link_state.locators,
306	                        link_state.sn,
307	                        link_state.links,
308	                        link_state.is_gateway,
309	                    ))
310	                } else {
311	                    match src_link.get_zid(&link_state.psid) {
312	                        Some(zid) => Some((
313	                            *zid,
314	                            link_state.whatami.unwrap_or(WhatAmI::Router),
315	                            link_state.locators,
316	                            link_state.sn,
317	                            link_state.links,
318	                            link_state.is_gateway,
319	                        )),
320	                        None => {
321	                            tracing::error!(
322	                                "Received LinkState from {} with unknown node mapping {}",
323	                                src,
324	                                link_state.psid
325	                            );
326	                            None
327	                        }
328	                    }
329	                }
330	            })
331	            .collect::<Vec<_>>();
332	
333	        for link_state in &link_states {
334	            tracing::trace!(
335	                "{} Received from {} mapped: {:?}",
336	                self.name,
337	                src,
338	                link_state
339	            );
340	        }
341	
342	        for (zid, whatami, locators, sn, _links, is_gateway) in link_states.into_iter() {
343	            if zid == src {
344	                let idx = match self.get_idx(&zid) {
345	                    None => {
346	                        let idx = self.add_node(Node {
347	                            zid,
348	                            whatami: Some(whatami),
349	                            locators: locators.clone(),
350	                            sn,
351	                            is_gateway,
352	                        });
353	                        locators.is_some().then_some(idx)
354	                    }
355	                    Some(idx) => {
356	                        let node = &mut self.graph[idx];
357	                        let oldsn = node.sn;
358	                        (oldsn < sn)
359	                            .then(|| {
360	                                node.sn = sn;
361	                                (node.locators != locators && locators.is_some()).then(|| {
362	                                    node.locators.clone_from(&locators);
363	                                    idx
364	                                })
365	                            })
366	                            .flatten()
367	                    }
368	                };
369	
370	                if let Some(idx) = idx {
371	                    self.send_on_links(
372	                        vec![(
373	                            idx,
374	                            Details {
375	                                zid: true,
376	                                locators: true,
377	                                links: false,
378	                            },
379	                        )],
380	                        |link| link.zid != zid,
381	                    );
382	                }
383	            }
384	
385	            if self.autoconnect.should_autoconnect(zid, whatami) {
386	                // Connect discovered peers (only if locators are available)
387	                if let Some(locators) = locators {
388	                    let runtime = strong_runtime.clone();
389	                    let wait_declares = self.wait_declares;
390	                    strong_runtime.spawn(async move {
391	                        if runtime
392	                            .manager()
393	                            .get_transport_unicast(&zid)
394	                            .await
395	                            .is_none()
396	                        {
397	                            runtime.start_conditions().add_peer_connector_zid(zid).await;
398	                            if runtime.connect_peer(&zid, &locators).await
399	                                && ((!wait_declares) || whatami != WhatAmI::Peer)
400	                            {
401	                                runtime
402	                                    .start_conditions()
403	                                    .terminate_peer_connector_zid(zid)
404	                                    .await;
405	                            }
406	                        }
407	                    });
408	                }
409	            }
410	        }
411	        if (!self.wait_declares) || src_whatami != WhatAmI::Peer {
412	            zenoh_runtime::ZRuntime::Net.block_in_place(
413	                strong_runtime
414	                    .start_conditions()
415	                    .terminate_peer_connector_zid(src),
416	            );
417	        }
418	    }
419	
420	    #[allow(clippy::incompatible_msrv)]
421	    pub(crate) fn add_link(&mut self, transport: TransportUnicast, remote_bound: Bound) -> usize {
422	        let free_index = {
423	            let mut i = 0;
424	            while self.links.contains_key(i) {
425	                i += 1;
426	            }
427	            i
428	        };
429	        self.links
430	            .insert(free_index, Link::new(transport.clone(), remote_bound));
431	
432	        let zid = transport.get_zid().unwrap();
433	        let whatami = transport.get_whatami().unwrap();
434	
435	        let (idx, new) = match self.get_idx(&zid) {
436	            Some(idx) => (idx, false),
437	            None => {
438	                tracing::debug!(
439	                    ?zid,
440	                    ?whatami,
441	                    ?remote_bound,
442	                    "{} Add node (link)",
443	                    self.name
444	                );
445	                (
446	                    self.add_node(Node {
447	                        zid,
448	                        whatami: Some(whatami),
449	                        locators: None,
450	                        sn: 0,
451	                        is_gateway: remote_bound.is_south(),
452	                    }),
453	                    true,
454	                )
455	            }
456	        };
457	        self.graph[self.idx].sn += 1;
458	
459	        // Send updated self linkstate on all existing links except new one
460	        self.links
461	            .values()
462	            .filter(|link| link.zid != zid && link.remote_bound.is_south())
463	            .for_each(|link| {
464	                self.send_on_link(
465	                    if new {
466	                        vec![
467	                            (
468	                                idx,
469	                                Details {
470	                                    zid: true,
471	                                    locators: false,
472	                                    links: false,
473	                                },
474	                            ),
475	                            (
476	                                self.idx,
477	                                Details {
478	                                    zid: false,
479	                                    locators: true,
480	                                    links: true,
481	                                },
482	                            ),
483	                        ]
484	                    } else {
485	                        vec![(
486	                            self.idx,
487	                            Details {
488	                                zid: false,
489	                                locators: true,
490	                                links: true,
491	                            },
492	                        )]
493	                    },
494	                    &link.transport,
495	                )
496	            });
497	
498	        // Send all nodes linkstate on new link
499	        let idxs = self
500	            .graph
501	            .node_indices()
502	            .map(|idx| {
503	                (
504	                    idx,
505	                    Details {
506	                        zid: true,
507	                        locators: true,
508	                        // NOTE(regions): peer gateway hats need link information to de-duplicate
509	                        // data/queries in the presence of multiple gateways. Links information is
510	                        // ignored by non-gateway peer remotes.
511	                        links: remote_bound.is_south(),
512	                    },
513	                )
514	            })
515	            .collect();
516	
517	        self.send_on_link(idxs, &transport);
518	        free_index
519	    }
520	
521	    pub(crate) fn remove_link(&mut self, zid: &ZenohIdProto) -> Vec<(NodeIndex, ZenohIdProto)> {
522	        tracing::trace!("{} remove_link {}", self.name, zid);
523	        self.links.retain(|_, link| link.zid != *zid);
524	
525	        if let Some(idx) = self.get_idx(zid) {
526	            self.graph.remove_node(idx);
527	        }
528	
529	        vec![]
530	    }
531	}
