428	    fn update_edge(&mut self, idx1: NodeIndex, idx2: NodeIndex) {
429	        use std::hash::Hasher;
430	        let mut hasher = std::collections::hash_map::DefaultHasher::default();
431	        let zid1 = self.graph[idx1].zid;
432	        let zid2 = self.graph[idx2].zid;
433	        if zid1 > zid2 {
434	            hasher.write(&self.graph[idx2].zid.to_le_bytes());
435	            hasher.write(&self.graph[idx1].zid.to_le_bytes());
436	        } else {
437	            hasher.write(&self.graph[idx1].zid.to_le_bytes());
438	            hasher.write(&self.graph[idx2].zid.to_le_bytes());
439	        }
440	        let w1 = self.graph[idx1]
441	            .links
442	            .iter()
443	            .find(|(dest, _weight)| *dest == &zid2)
444	            .and_then(|(_dest, weight)| weight.is_set().then_some(weight.value()));
445	        let w2 = self.graph[idx2]
446	            .links
447	            .iter()
448	            .find(|(dest, _weight)| *dest == &zid1)
449	            .and_then(|(_dest, weight)| weight.is_set().then_some(weight.value()));
450	        let w = match (w1, w2) {
451	            (None, None) => LinkEdgeWeight::default().value(),
452	            (None, Some(w2)) => w2,
453	            (Some(w1), None) => w1,
454	            (Some(w1), Some(w2)) => w1.max(w2),
455	        };
456	        let weight =
457	            w as f64 * (1.0 + 0.01 * (((hasher.finish() as u32) as f64) / u32::MAX as f64));
458	        self.graph.update_edge(idx1, idx2, weight);
459	    }
